package buffer

type Ring struct {
	data  []int
	cap   int
	head  int
	tail  int
	count int
}

func NewRing(capacity int) *Ring {
	return &Ring{
		data: make([]int, capacity),
		cap:  capacity,
	}
}

func (r *Ring) Write(val int) {
	r.data[r.tail] = val
	r.tail = (r.tail + 1) % r.cap
	if r.count == r.cap {
		// Overwrite: advance head
		r.head = (r.head + 1) % r.cap
	} else {
		r.count++
	}
}

func (r *Ring) Read() (int, bool) {
	if r.count == 0 {
		return 0, false
	}
	val := r.data[r.head]
	r.head = (r.head + 1) % r.cap
	r.count--
	return val, true
}

func (r *Ring) Len() int {
	return r.count
}
